Iteratively try each order on all existing non-empty assigns sorted by current route proximity to pickup location; if none accepts, insert into the first empty assign or append a new empty assign as fallback.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		idx       int
		addedCost float64
	}
	for jj := 0; jj < len(oris); jj++ {
		bestCand := candidate{idx: -1, addedCost: 1e18}
		fallbackIdx := -1
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			oldCost := dispatch.Assigns[ii].Cost
			if dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				dispatch.Assigns[ii].GenRoute()
				if dispatch.Assigns[ii].Cost >= 0 {
					delta := dispatch.Assigns[ii].Cost - oldCost
					if delta < bestCand.addedCost {
						bestCand.idx = ii
						bestCand.addedCost = delta
					}
				}
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			}
		}
		inserted := false
		if bestCand.idx != -1 {
			ok := dispatch.Assigns[bestCand.idx].AddShip(total_ship+jj, oris[jj], dess[jj])
			if ok {
				dispatch.Assigns[bestCand.idx].GenRoute()
				if dispatch.Assigns[bestCand.idx].Cost >= 0 {
					inserted = true
				} else {
					dispatch.Assigns[bestCand.idx].RemoveShip(total_ship + jj)
					dispatch.Assigns[bestCand.idx].GenRoute()
				}
			}
		}
		if !inserted {
			for ee := 0; ee <= dispatch.AssignsLen && ee < MAXASSIGNS; ee++ {
				if ee == dispatch.AssignsLen {
					fallbackIdx = ee
					break
				}
				if dispatch.Assigns[ee].StationsLen == 0 {
					fallbackIdx = ee
					break
				}
			}
			if fallbackIdx != -1 {
				ok := dispatch.Assigns[fallbackIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
				if ok {
					dispatch.Assigns[fallbackIdx].GenRoute()
					if dispatch.Assigns[fallbackIdx].Cost >= 0 {
						inserted = true
						if fallbackIdx >= dispatch.AssignsLen {
							dispatch.AssignsLen = fallbackIdx + 1
						}
					} else {
						dispatch.Assigns[fallbackIdx].RemoveShip(total_ship + jj)
						dispatch.Assigns[fallbackIdx].GenRoute()
					}
				}
			}
		}
		if !inserted {
			newIdx := dispatch.AssignsLen
			if newIdx < MAXASSIGNS {
				ok := dispatch.Assigns[newIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
				if ok {
					dispatch.Assigns[newIdx].GenRoute()
					if dispatch.Assigns[newIdx].Cost >= 0 {
						dispatch.AssignsLen++
					} else {
						dispatch.Assigns[newIdx].RemoveShip(total_ship + jj)
						dispatch.Assigns[newIdx].GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

